{
  "schema_version": "patch_intent.v1",
  "intents": [
    {
      "intent_id": "replace_current_behavior",
      "operation": "replace-heading-section",
      "target": {
        "target_file_guess": "docs/example.md",
        "heading_path": [
          "Example",
          "Current Behavior"
        ],
        "frontmatter_required": false
      },
      "replacement": {
        "content": "updated behavior\n",
        "content_role": "section_body",
        "preserve_surrounding_formatting": true
      },
      "validation": {
        "expected_phrases": [
          "updated behavior"
        ],
        "forbidden_phrases": [
          "current behavior"
        ]
      },
      "safety": {
        "require_unique_match": true,
        "fail_on_ambiguity": true,
        "allow_full_file_rewrite": false,
        "max_files_touched": 1
      },
      "notes": "Fixture-owned sample intent; created by fixture_spec.template.json so fixture_runner.py can execute commands without missing files."
    }
  ]
}
